#if swift(>=5.8)
@_documentation(visibility: private)
#endif
public struct FfiConverterTypeMarmot: FfiConverter {

    typealias FfiType = UnsafeMutableRawPointer
    typealias SwiftType = Marmot

    public static func lift(_ pointer: UnsafeMutableRawPointer) throws -> Marmot {
        return Marmot(unsafeFromRawPointer: pointer)
    }

    public static func lower(_ value: Marmot) -> UnsafeMutableRawPointer {
        return value.uniffiClonePointer()
    }

    public static func read(from buf: inout (data: Data, offset: Data.Index)) throws -> Marmot {
        let v: UInt64 = try readInt(&buf)
        // The Rust code won't compile if a pointer won't fit in a UInt64.
        // We have to go via `UInt` because that's the thing that's the size of a pointer.
        let ptr = UnsafeMutableRawPointer(bitPattern: UInt(truncatingIfNeeded: v))
        if (ptr == nil) {
            throw UniffiInternalError.unexpectedNullPointer
        }
        return try lift(ptr!)
    }

    public static func write(_ value: Marmot, into buf: inout [UInt8]) {
        // This fiddling is because `Int` is the thing that's the same size as a pointer.
        // The Rust code won't compile if a pointer won't fit in a `UInt64`.
        writeInt(&buf, UInt64(bitPattern: Int64(Int(bitPattern: lower(value)))))
    }
}




#if swift(>=5.8)
@_documentation(visibility: private)
#endif
public func FfiConverterTypeMarmot_lift(_ pointer: UnsafeMutableRawPointer) throws -> Marmot {
    return try FfiConverterTypeMarmot.lift(pointer)
}

#if swift(>=5.8)
@_documentation(visibility: private)
#endif
public func FfiConverterTypeMarmot_lower(_ value: Marmot) -> UnsafeMutableRawPointer {
    return FfiConverterTypeMarmot.lower(value)
}




public protocol MessagesSubscriptionProtocol : AnyObject {

    func next() async  -> MessageUpdateFfi?

    func snapshot()  -> [AppMessageRecordFfi]

}

open class MessagesSubscription:
    MessagesSubscriptionProtocol {
    fileprivate let pointer: UnsafeMutableRawPointer!

    /// Used to instantiate a [FFIObject] without an actual pointer, for fakes in tests, mostly.
#if swift(>=5.8)
    @_documentation(visibility: private)
#endif
    public struct NoPointer {
        public init() {}
    }

    // TODO: We'd like this to be `private` but for Swifty reasons,
    // we can't implement `FfiConverter` without making this `required` and we can't
    // make it `required` without making it `public`.
    required public init(unsafeFromRawPointer pointer: UnsafeMutableRawPointer) {
        self.pointer = pointer
    }

    // This constructor can be used to instantiate a fake object.
    // - Parameter noPointer: Placeholder value so we can have a constructor separate from the default empty one that may be implemented for classes extending [FFIObject].
    //
    // - Warning:
    //     Any object instantiated with this constructor cannot be passed to an actual Rust-backed object. Since there isn't a backing [Pointer] the FFI lower functions will crash.
#if swift(>=5.8)
    @_documentation(visibility: private)
#endif
    public init(noPointer: NoPointer) {
        self.pointer = nil
    }

#if swift(>=5.8)
    @_documentation(visibility: private)
#endif
    public func uniffiClonePointer() -> UnsafeMutableRawPointer {
        return try! rustCall { uniffi_marmot_uniffi_fn_clone_messagessubscription(self.pointer, $0) }
    }
    // No primary constructor declared for this class.

    deinit {
        guard let pointer = pointer else {
            return
        }

        try! rustCall { uniffi_marmot_uniffi_fn_free_messagessubscription(pointer, $0) }
    }




open func next()async  -> MessageUpdateFfi? {
    return
        try!  await uniffiRustCallAsync(
            rustFutureFunc: {
                uniffi_marmot_uniffi_fn_method_messagessubscription_next(
                    self.uniffiClonePointer()

                )
            },
            pollFunc: ffi_marmot_uniffi_rust_future_poll_rust_buffer,
            completeFunc: ffi_marmot_uniffi_rust_future_complete_rust_buffer,
            freeFunc: ffi_marmot_uniffi_rust_future_free_rust_buffer,
            liftFunc: FfiConverterOptionTypeMessageUpdateFfi.lift,
            errorHandler: nil

        )
}

